/// 0000-DALYTRAN-OPEN
fn p_0000_dalytran_open(state: &mut ProgramState) {
    p_0100_tranfile_open(state);
    p_0200_xreffile_open(state);
    p_0300_dalyrejs_open(state);
    p_0400_acctfile_open(state);
    p_0500_tcatbalf_open(state);
    while !(&format!("{}", state.end_of_file) == &"Y".to_string()) {
        // SKIP: unresolved ref
    }
    p_9000_dalytran_close(state);
    p_9100_tranfile_close(state);
    p_9200_xreffile_close(state);
    p_9300_dalyrejs_close(state);
    p_9400_acctfile_close(state);
    p_9500_tcatbalf_close(state);
    println!("{}{}", "TRANSACTIONS PROCESSED :", state.ws_counters.ws_transaction_count);
    println!("{}{}", "TRANSACTIONS REJECTED  :", state.ws_counters.ws_reject_count);
    if state.ws_counters.ws_reject_count > 0 {
        state.return_code = 4 as i32;
    }
    println!("{}", "END OF EXECUTION OF PROGRAM CBTRN02C");
    { let _ = state._fh_dalytran_file.close();
        let _ = state._fh_transact_file.close();
        let _ = state._fh_xref_file.close();
        let _ = state._fh_dalyrejs_file.close();
        let _ = state._fh_account_file.close();
        let _ = state._fh_tcatbal_file.close();
        return; }
}

/// 0000-DALYTRAN-OPEN
fn p_0000_dalytran_open_2(state: &mut ProgramState) {
    state.appl_result = 8 as i32;
    dalytran_file_open_input(state);
    if { let _s = format!("{}", state.dalytran_status); _s.trim().to_string() } == "00".to_string() {
        state.appl_result = 0 as i32;
    } else {
        state.appl_result = 12 as i32;
    }
    if state.appl_result == 0 {
    } else {
        println!("{}", "ERROR OPENING DALYTRAN");
        {
            let mut _bytes = vec![b' '; 2];
            { let _src = state.dalytran_status.dalytran_stat1.as_bytes(); let _end = (0+1).min(_bytes.len()); let _cl = _src.len().min(_end-0); _bytes[0..0+_cl].copy_from_slice(&_src[.._cl]); }
            { let _src = state.dalytran_status.dalytran_stat2.as_bytes(); let _end = (1+1).min(_bytes.len()); let _cl = _src.len().min(_end-1); _bytes[1..1+_cl].copy_from_slice(&_src[.._cl]); }
            let _len = _bytes.len();
            if _len > 0 { let _end = _len.min(0+1); state.io_status.io_stat1 = FixedString::from(String::from_utf8_lossy(&_bytes[0.._end])); }
            if _len > 1 { let _end = _len.min(1+1); state.io_status.io_stat2 = FixedString::from(String::from_utf8_lossy(&_bytes[1.._end])); }
        }
        p_9910_display_io_status(state);
        p_9999_abend_program(state);
    }
}

