/// 1500-B-LOOKUP-ACCT
fn p_1500_b_lookup_acct(state: &mut ProgramState) {
    state.fd_acct_id = state.card_xref_record.xref_acct_id.clone();
    account_file_read(state);
    state.ws_validation_trailer.ws_validation_fail_reason = 101 as u32;
    state.ws_validation_trailer.ws_validation_fail_reason_desc = "ACCOUNT RECORD NOT FOUND".into();
    state.ws_counters.ws_temp_bal = Decimal::from(i64::from(state.account_record.acct_curr_cyc_credit - state.account_record.acct_curr_cyc_debit + state.dalytran_record.dalytran_amt));
    if state.account_record.acct_credit_limit >= state.ws_counters.ws_temp_bal {
    } else {
        state.ws_validation_trailer.ws_validation_fail_reason = 102 as u32;
        state.ws_validation_trailer.ws_validation_fail_reason_desc = "OVERLIMIT TRANSACTION".into();
    }
    if state.account_record.acct_expiraion_date >= { let _rm_b = state.dalytran_record.dalytran_orig_ts.as_bytes().to_vec(); String::from_utf8(_rm_b[(1 - 1) as usize..(1 - 1 + 10) as usize].to_vec()).unwrap_or_default() } {
    } else {
        state.ws_validation_trailer.ws_validation_fail_reason = 103 as u32;
        state.ws_validation_trailer.ws_validation_fail_reason_desc = "TRANSACTION RECEIVED AFTER ACCT EXPIRATION".into();
    }
}

